const { sendgrid } = require('@sendgrid/mail');
const stripe = require('stripe')(process.env.STRIPE_SECRET_KEY);

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
  try {
    const url = new URL(request.url);
    const pathname = url.pathname;

    if (pathname === '/api/send-email') {
      // Send email using SendGrid API
      const email = await sendgrid.send({
        to: 'recipient@example.com',
        from: 'sender@example.com',
        subject: 'Hello from Cloudflare Workers!',
        text: 'This is a test email sent from Cloudflare Workers!'
      });

      return new Response(JSON.stringify({ message: 'Email sent successfully' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    } else if (pathname === '/api/make-payment') {
      // Make payment using Stripe API
      const payment = await stripe.charges.create({
        amount: 100,
        currency: 'usd',
        source: request.body.source,
        description: 'Test payment'
      });

      return new Response(JSON.stringify({ message: 'Payment successful' }), {
        status: 200,
        headers: { 'Content-Type': 'application/json' }
      });
    } else {
      return new Response('Not found', { status: 404 });
    }
  } catch (error) {
    console.log(error);
    return new Response('Internal server error', { status: 500 });
  }
}